import{gt as e,nt as t,s as n,tt as r}from"./chunks/framework.BqU7tCwc.js";var i=JSON.parse(`{"title":"everything-claude-code Java 项目接入调研结论","description":"","frontmatter":{"title":"everything-claude-code Java 项目接入调研结论"},"headers":[],"relativePath":"ai/coding/everything-claude-code.md","filePath":"ai/coding/everything-claude-code.md","lastUpdated":1784620663000}`),a={name:`ai/coding/everything-claude-code.md`};function o(n,i,a,o,s,c){return e(),r(`div`,null,[...i[0]||=[t(`<h1 id="everything-claude-code-java-项目接入调研结论" tabindex="-1">everything-claude-code Java 项目接入调研结论 <a class="header-anchor" href="#everything-claude-code-java-项目接入调研结论" aria-label="Permalink to “everything-claude-code Java 项目接入调研结论”">​</a></h1><h2 id="推荐决策" tabindex="-1">推荐决策 <a class="header-anchor" href="#推荐决策" aria-label="Permalink to “推荐决策”">​</a></h2><p>建议优先落地 <strong>“3 Agents + 3 Skills + 2 Commands + 2 Rules”</strong> 最小可用组合。</p><p>先在 1～2 个 Java / Spring Boot 项目中完成 <strong>两周试点验证</strong>，验证通过后，再按照 <strong>Java 能力白名单</strong> 逐步扩展接入范围。</p><hr><h2 id="_1-调研背景" tabindex="-1">1. 调研背景 <a class="header-anchor" href="#_1-调研背景" aria-label="Permalink to “1. 调研背景”">​</a></h2><p>团队计划评估 <code>everything-claude-code</code> 在 Java 项目中的可用能力，重点关注其在 Java / Spring Boot 项目中的代码审查、构建排查、测试补齐、安全检查等场景的复用价值。</p><p>本次调研的核心原则是：</p><ol><li>优先复用 Java / Spring 相关能力。</li><li>避免引入 TypeScript / Node.js 专属链路。</li><li>降低接入成本，避免工具能力过宽导致误用。</li><li>以最小可用组合先试点，再逐步扩展。</li></ol><hr><h2 id="_2-调研目标" tabindex="-1">2. 调研目标 <a class="header-anchor" href="#_2-调研目标" aria-label="Permalink to “2. 调研目标”">​</a></h2><p>本次调研主要回答以下问题：</p><ol><li>哪些 Agents / Skills / Commands / Rules 可以直接复用？</li><li>哪些能力适合进入 Java 项目的最小可用组合？</li><li>哪些能力需要裁剪、改造后再接入？</li><li>哪些能力不建议直接引入？</li><li>如何制定后续试点与扩展路径？</li></ol><hr><h2 id="_3-调研结论" tabindex="-1">3. 调研结论 <a class="header-anchor" href="#_3-调研结论" aria-label="Permalink to “3. 调研结论”">​</a></h2><h3 id="_3-1-总体结论" tabindex="-1">3.1 总体结论 <a class="header-anchor" href="#_3-1-总体结论" aria-label="Permalink to “3.1 总体结论”">​</a></h3><p>不建议将 <code>everything-claude-code</code> 整套直接引入 Java 项目。</p><p>更推荐采用 <strong>“Java 能力白名单”</strong> 的方式分批接入，只引入与 Java / Spring Boot 项目强相关的能力，避免 TypeScript / Node.js 相关规则、命令和流程污染现有研发链路。</p><h3 id="_3-2-接入策略" tabindex="-1">3.2 接入策略 <a class="header-anchor" href="#_3-2-接入策略" aria-label="Permalink to “3.2 接入策略”">​</a></h3><p>建议按照以下策略推进：</p><ol><li><strong>先试点最小组合</strong>：优先接入 Java 代码审查、构建排查、测试验证、安全检查相关能力。</li><li><strong>再扩展中优先级能力</strong>：对通用审查、数据库审查、编码规范、架构模式等能力进行裁剪后接入。</li><li><strong>明确排除 TS / Node 专属能力</strong>：避免引入 Next.js、NestJS、Bun、TypeScript 构建等与当前 Java 项目无关的能力。</li></ol><hr><h2 id="_4-最小可用组合" tabindex="-1">4. 最小可用组合 <a class="header-anchor" href="#_4-最小可用组合" aria-label="Permalink to “4. 最小可用组合”">​</a></h2><p>建议优先落地以下组合：</p><table tabindex="0"><thead><tr><th>类型</th><th>推荐项</th></tr></thead><tbody><tr><td>Agents</td><td><code>java-reviewer</code>、<code>java-build-resolver</code>、<code>security-reviewer</code></td></tr><tr><td>Skills</td><td><code>springboot-patterns</code>、<code>springboot-tdd</code>、<code>springboot-verification</code></td></tr><tr><td>Commands</td><td><code>build-fix</code>、<code>test-coverage</code></td></tr><tr><td>Rules</td><td><code>rules/java/security.md</code>、<code>rules/java/testing.md</code></td></tr></tbody></table><h3 id="_4-1-推荐理由" tabindex="-1">4.1 推荐理由 <a class="header-anchor" href="#_4-1-推荐理由" aria-label="Permalink to “4.1 推荐理由”">​</a></h3><p>该组合覆盖 Java 项目试点阶段最核心的四类场景：</p><ol><li><strong>代码审查</strong>：检查 Java / Spring Boot 代码质量、分层边界、异常处理、事务使用等问题。</li><li><strong>构建修复</strong>：辅助排查 Maven / Gradle 依赖冲突、编译失败、测试失败等问题。</li><li><strong>测试补齐</strong>：推动 JUnit 5、Mockito、MockMvc、Testcontainers 等测试能力落地。</li><li><strong>安全检查</strong>：覆盖常见 Java Web 安全问题，如鉴权、越权、SQL 注入、敏感信息泄露等。</li></ol><hr><h2 id="_5-详细适配清单" tabindex="-1">5. 详细适配清单 <a class="header-anchor" href="#_5-详细适配清单" aria-label="Permalink to “5. 详细适配清单”">​</a></h2><h3 id="_5-1-agents-适配清单" tabindex="-1">5.1 Agents 适配清单 <a class="header-anchor" href="#_5-1-agents-适配清单" aria-label="Permalink to “5.1 Agents 适配清单”">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th style="text-align:right;">适配优先级</th><th>适配建议</th></tr></thead><tbody><tr><td><code>java-reviewer</code></td><td style="text-align:right;">高</td><td>可直接用于 Java / Spring Boot 代码审查。</td></tr><tr><td><code>java-build-resolver</code></td><td style="text-align:right;">高</td><td>可直接用于 Maven / Gradle 构建、依赖、测试失败等问题排查。</td></tr><tr><td><code>security-reviewer</code></td><td style="text-align:right;">中</td><td>安全审查方法可复用，但需要补充 Java 技术栈相关检查项。</td></tr><tr><td><code>code-reviewer</code></td><td style="text-align:right;">中</td><td>通用审查流程可参考，但需要弱化 TypeScript / Node.js 假设。</td></tr><tr><td><code>database-reviewer</code></td><td style="text-align:right;">中</td><td>PostgreSQL 相关能力偏强，建模、索引、SQL 审查方法可参考。</td></tr></tbody></table><h4 id="重点建议" tabindex="-1">重点建议 <a class="header-anchor" href="#重点建议" aria-label="Permalink to “重点建议”">​</a></h4><p>优先接入：</p><ul><li><code>java-reviewer</code></li><li><code>java-build-resolver</code></li><li><code>security-reviewer</code></li></ul><p>暂缓接入：</p><ul><li><code>code-reviewer</code></li><li><code>database-reviewer</code></li></ul><p>这两个更适合作为第二阶段扩展能力，先完成裁剪后再引入。</p><hr><h3 id="_5-2-skills-适配清单" tabindex="-1">5.2 Skills 适配清单 <a class="header-anchor" href="#_5-2-skills-适配清单" aria-label="Permalink to “5.2 Skills 适配清单”">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th style="text-align:right;">适配优先级</th><th>适配建议</th></tr></thead><tbody><tr><td><code>springboot-patterns</code></td><td style="text-align:right;">高</td><td>可直接复用，用于规范 Spring Boot 分层、Controller / Service / Repository 设计。</td></tr><tr><td><code>springboot-tdd</code></td><td style="text-align:right;">高</td><td>可直接复用，适用于 JUnit 5、Mockito、MockMvc、Testcontainers 等测试场景。</td></tr><tr><td><code>springboot-verification</code></td><td style="text-align:right;">高</td><td>可直接复用，用于构建、测试、覆盖率、安全扫描闭环。</td></tr><tr><td><code>springboot-security</code></td><td style="text-align:right;">中</td><td>安全基线可参考，但需要结合当前鉴权、网关和权限模型调整。</td></tr><tr><td><code>java-coding-standards</code></td><td style="text-align:right;">中</td><td>偏 JDK 17 规范，建议结合团队当前 JDK 版本裁剪。</td></tr></tbody></table><h4 id="重点建议-1" tabindex="-1">重点建议 <a class="header-anchor" href="#重点建议-1" aria-label="Permalink to “重点建议”">​</a></h4><p>优先接入：</p><ul><li><code>springboot-patterns</code></li><li><code>springboot-tdd</code></li><li><code>springboot-verification</code></li></ul><p>第二阶段接入：</p><ul><li><code>springboot-security</code></li><li><code>java-coding-standards</code></li></ul><hr><h3 id="_5-3-commands-适配清单" tabindex="-1">5.3 Commands 适配清单 <a class="header-anchor" href="#_5-3-commands-适配清单" aria-label="Permalink to “5.3 Commands 适配清单”">​</a></h3><table tabindex="0"><thead><tr><th>Command</th><th style="text-align:right;">适配优先级</th><th>适配建议</th></tr></thead><tbody><tr><td><code>build-fix</code></td><td style="text-align:right;">中</td><td>流程可用，建议补充 Java 常见构建故障场景。</td></tr><tr><td><code>test-coverage</code></td><td style="text-align:right;">中</td><td>建议以 JaCoCo + Maven / Gradle 作为主线配置。</td></tr></tbody></table><h4 id="java-项目建议补充的构建故障场景" tabindex="-1">Java 项目建议补充的构建故障场景 <a class="header-anchor" href="#java-项目建议补充的构建故障场景" aria-label="Permalink to “Java 项目建议补充的构建故障场景”">​</a></h4><p><code>build-fix</code> 建议补充以下 Java 常见问题：</p><ol><li>Maven / Gradle 依赖冲突。</li><li>多模块项目依赖顺序问题。</li><li>JDK 版本不一致。</li><li>Spring Boot 版本与依赖版本不兼容。</li><li>Lombok / MapStruct / Annotation Processor 编译问题。</li><li>单元测试失败导致构建失败。</li><li>CI 环境与本地环境不一致。</li></ol><hr><h3 id="_5-4-rules-适配清单" tabindex="-1">5.4 Rules 适配清单 <a class="header-anchor" href="#_5-4-rules-适配清单" aria-label="Permalink to “5.4 Rules 适配清单”">​</a></h3><table tabindex="0"><thead><tr><th>Rule</th><th style="text-align:right;">适配优先级</th><th>适配建议</th></tr></thead><tbody><tr><td><code>rules/java/security.md</code></td><td style="text-align:right;">高</td><td>可作为 Java 安全基线。</td></tr><tr><td><code>rules/java/testing.md</code></td><td style="text-align:right;">高</td><td>可作为 Java 测试基线。</td></tr><tr><td><code>rules/java/coding-style.md</code></td><td style="text-align:right;">中</td><td>需要结合团队编码规范与 JDK 版本裁剪。</td></tr><tr><td><code>rules/java/patterns.md</code></td><td style="text-align:right;">中</td><td>需要结合现有架构约束调整。</td></tr><tr><td><code>rules/java/hooks.md</code></td><td style="text-align:right;">中</td><td>需要结合现有 CI / Hook 流程落地。</td></tr></tbody></table><h4 id="重点建议-2" tabindex="-1">重点建议 <a class="header-anchor" href="#重点建议-2" aria-label="Permalink to “重点建议”">​</a></h4><p>试点阶段只接入：</p><ul><li><code>rules/java/security.md</code></li><li><code>rules/java/testing.md</code></li></ul><p>暂缓接入：</p><ul><li><code>rules/java/coding-style.md</code></li><li><code>rules/java/patterns.md</code></li><li><code>rules/java/hooks.md</code></li></ul><p>原因是这三类规则与团队既有规范、架构边界、CI 流程关系更强，直接引入容易产生冲突，建议在第二阶段结合团队现状裁剪后再接入。</p><hr><h2 id="_6-不建议直接引入的能力" tabindex="-1">6. 不建议直接引入的能力 <a class="header-anchor" href="#_6-不建议直接引入的能力" aria-label="Permalink to “6. 不建议直接引入的能力”">​</a></h2><p>以下能力不建议直接引入 Java 项目：</p><ul><li><code>agents/typescript-reviewer.md</code></li><li><code>agents/build-error-resolver.md</code></li><li><code>rules/typescript/*</code></li><li><code>nextjs-turbopack</code></li><li><code>nestjs-patterns</code></li><li><code>bun-runtime</code></li></ul><h3 id="_6-1-排除原因" tabindex="-1">6.1 排除原因 <a class="header-anchor" href="#_6-1-排除原因" aria-label="Permalink to “6.1 排除原因”">​</a></h3><ol><li>这些能力主要面向 TypeScript / Node.js 技术栈。</li><li>与 Java / Spring Boot 项目的研发流程不匹配。</li><li>容易引入错误的工程假设，例如 npm、pnpm、bun、tsconfig、Next.js 构建链路等。</li><li>会增加团队理解成本和误用风险。</li><li>对 Java 项目试点验证价值较低。</li></ol><hr><h2 id="_7-试点落地建议" tabindex="-1">7. 试点落地建议 <a class="header-anchor" href="#_7-试点落地建议" aria-label="Permalink to “7. 试点落地建议”">​</a></h2><h3 id="_7-1-试点周期" tabindex="-1">7.1 试点周期 <a class="header-anchor" href="#_7-1-试点周期" aria-label="Permalink to “7.1 试点周期”">​</a></h3><p>建议试点周期为 <strong>两周</strong>。</p><h3 id="_7-2-试点范围" tabindex="-1">7.2 试点范围 <a class="header-anchor" href="#_7-2-试点范围" aria-label="Permalink to “7.2 试点范围”">​</a></h3><p>建议选择 1～2 个 Java / Spring Boot 项目作为试点对象，优先选择满足以下条件的项目：</p><ol><li>使用 Maven 或 Gradle 构建。</li><li>有一定单元测试或集成测试基础。</li><li>存在代码审查、测试补齐、构建排查等实际需求。</li><li>项目复杂度适中，不建议一开始选择核心链路最复杂的项目。</li></ol><h3 id="_7-3-试点验证内容" tabindex="-1">7.3 试点验证内容 <a class="header-anchor" href="#_7-3-试点验证内容" aria-label="Permalink to “7.3 试点验证内容”">​</a></h3><p>试点期间重点验证以下内容：</p><ol><li><code>java-reviewer</code> 是否能稳定发现代码质量问题。</li><li><code>java-build-resolver</code> 是否能辅助定位 Maven / Gradle 构建问题。</li><li><code>security-reviewer</code> 是否能识别常见 Java Web 安全风险。</li><li><code>springboot-tdd</code> 是否能提升测试用例补齐效率。</li><li><code>springboot-verification</code> 是否能形成构建、测试、覆盖率、安全扫描闭环。</li><li><code>build-fix</code> 和 <code>test-coverage</code> 是否适配现有 CI 流程。</li></ol><hr><h2 id="_8-后续计划" tabindex="-1">8. 后续计划 <a class="header-anchor" href="#_8-后续计划" aria-label="Permalink to “8. 后续计划”">​</a></h2><h3 id="_8-1-补齐-java-能力映射表" tabindex="-1">8.1 补齐 Java 能力映射表 <a class="header-anchor" href="#_8-1-补齐-java-能力映射表" aria-label="Permalink to “8.1 补齐 Java 能力映射表”">​</a></h3><p>建议补充完整映射关系：</p><p><strong>能力 -&gt; 项目职责 -&gt; 落地位置 -&gt; 使用场景 -&gt; 验收标准</strong></p><p>示例：</p><table tabindex="0"><thead><tr><th>能力</th><th>项目职责</th><th>落地位置</th><th>验收标准</th></tr></thead><tbody><tr><td><code>java-reviewer</code></td><td>Java 代码审查</td><td>Code Review 阶段</td><td>能识别常见代码质量和 Spring 使用问题。</td></tr><tr><td><code>java-build-resolver</code></td><td>构建问题排查</td><td>本地构建 / CI 失败后</td><td>能辅助定位 Maven / Gradle 失败原因。</td></tr><tr><td><code>springboot-tdd</code></td><td>测试用例生成</td><td>开发与测试补齐阶段</td><td>能生成可运行、可维护的 JUnit 5 测试。</td></tr></tbody></table><h3 id="_8-2-明确版本前提" tabindex="-1">8.2 明确版本前提 <a class="header-anchor" href="#_8-2-明确版本前提" aria-label="Permalink to “8.2 明确版本前提”">​</a></h3><p>需要确认以下版本信息：</p><ol><li>JDK 版本。</li><li>Spring Boot 版本。</li><li>Maven / Gradle 版本。</li><li>JUnit / Mockito / Testcontainers 版本。</li><li>JaCoCo 覆盖率工具版本。</li><li>安全扫描工具版本。</li></ol><h3 id="_8-3-增加落地检查清单" tabindex="-1">8.3 增加落地检查清单 <a class="header-anchor" href="#_8-3-增加落地检查清单" aria-label="Permalink to “8.3 增加落地检查清单”">​</a></h3><p>建议补充以下检查项：</p><ol><li>Hook 是否接入。</li><li>CI 是否接入。</li><li>测试覆盖率阈值是否明确。</li><li>安全扫描规则是否明确。</li><li>代码审查门禁是否明确。</li><li>误报处理机制是否明确。</li><li>白名单扩展流程是否明确。</li></ol><h3 id="_8-4-明确迁移边界" tabindex="-1">8.4 明确迁移边界 <a class="header-anchor" href="#_8-4-明确迁移边界" aria-label="Permalink to “8.4 明确迁移边界”">​</a></h3><p>需要提前确认以下边界：</p><ol><li>哪些流程沿用 <code>everything-claude-code</code>。</li><li>哪些流程保留团队现有实现。</li><li>哪些规则必须裁剪后才能使用。</li><li>哪些能力只作为参考，不进入正式链路。</li><li>哪些能力进入试点，哪些能力进入第二阶段。</li></ol><hr><h2 id="_9-最终建议" tabindex="-1">9. 最终建议 <a class="header-anchor" href="#_9-最终建议" aria-label="Permalink to “9. 最终建议”">​</a></h2><p>本次接入不建议追求“大而全”，而应采用 <strong>小范围、白名单、可验证</strong> 的方式推进。</p><p>推荐路径如下：</p><ol><li>第一阶段：接入最小可用组合。</li><li>第二阶段：完成两周试点验证。</li><li>第三阶段：沉淀 Java 能力映射表与检查清单。</li><li>第四阶段：按白名单扩展更多 Agents / Skills / Rules。</li></ol><p>最终目标不是直接复用 <code>everything-claude-code</code> 的全部能力，而是沉淀一套适合当前团队 Java / Spring Boot 项目的 AI 辅助研发能力体系。</p>`,99)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};